labs.cli:
# Health check on the primary endpoint
aws route53 create-health-check \
  --caller-reference hc-primary-$(date +%s) \
  --health-check-config Type=HTTPS,FullyQualifiedDomainName=primary.example.com,Port=443,ResourcePath=/health,RequestInterval=30,FailureThreshold=3

# Primary A/Alias record (PRIMARY, references the health check)
aws route53 change-resource-record-sets --hosted-zone-id Z123456ABCDEFG --change-batch '{
  "Changes":[{"Action":"UPSERT","ResourceRecordSet":{
    "Name":"app.example.com","Type":"A","TTL":60,
    "SetIdentifier":"primary","Failover":"PRIMARY",
    "HealthCheckId":"abcd-1234",
    "ResourceRecords":[{"Value":"203.0.113.10"}]
  }}]}'

# Secondary record (SECONDARY)
aws route53 change-resource-record-sets --hosted-zone-id Z123456ABCDEFG --change-batch '{
  "Changes":[{"Action":"UPSERT","ResourceRecordSet":{
    "Name":"app.example.com","Type":"A","TTL":60,
    "SetIdentifier":"secondary","Failover":"SECONDARY",
    "ResourceRecords":[{"Value":"198.51.100.20"}]
  }}]}'
